const src = $json;
const subject = src.subject || '';
const preview = src.bodyPreview || '';
const body = src.body?.content || src.body || '';
const joined = `${subject}\n${preview}\n${body}`;
const match = joined.match(/AN-\d{4,5}/i);
const an = match ? match[0].toUpperCase() : null;

return [{
  json: {
    mailbox: 'asr@cargolo.com',
    an,
    trigger_message_id: src.internetMessageId || null,
    trigger_graph_id: src.id || null,
    trigger_conversation_id: src.conversationId || null,
    source_mail: src
  },
  binary: $binary
}];

function getBinaryAttachments(binary) {
  if (!binary) return [];

  return Object.entries(binary).map(([key, file]) => ({
    field_name: key,
    filename: file.fileName || null,
    mime_type: file.mimeType || null,
    size: file.fileSize || null,
    content_base64: file.data || null,
  }));
}

function htmlToText(html) {
  if (!html || typeof html !== 'string') return '';

  return html
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<head[\s\S]*?<\/head>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<\/td>/gi, ' ')
    .replace(/<li>/gi, '- ')
    .replace(/<\/li>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\r/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function cleanMailText(text) {
  if (!text || typeof text !== 'string') return '';

  let cleaned = text;

  cleaned = cleaned.replace(
    /^ACHTUNG:\sDiese Mail wurde von extern empfangen\.[\s\S]?Hartmann IT-Wiki\s*/i,
    ''
  );

  cleaned = cleaned.replace(
    /\n\sBei Fragen erreichen Sie uns unter[\s\S]$/i,
    ''
  );

  cleaned = cleaned.replace(
    /\n\swww\.cargolo\.com[\s\S]$/i,
    ''
  );

  cleaned = cleaned.replace(
    /\n\sCARGOLO GmbH[\s\S]$/i,
    ''
  );

  cleaned = cleaned.replace(/https?:\/\/\S+/gi, (url) => {
    if (/pstmrk\.it|shorturl\.at/i.test(url)) return '';
    return url;
  });

  cleaned = cleaned
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return cleaned;
}

const item = $input.first();
const seed = item.json;
const mail = seed.source_mail || {};
const attachments = getBinaryAttachments(item.binary || {});

const contentType = mail.body?.contentType || null;
const bodyContent = mail.body?.content || '';

const body_html = contentType === 'html' ? bodyContent : '';
const raw_text =
  contentType === 'text'
    ? bodyContent
    : htmlToText(bodyContent);

const body_text = cleanMailText(raw_text);

const message = {
  message_id: mail.internetMessageId || null,
  graph_id: mail.id || null,
  conversation_id: mail.conversationId || null,
  subject: mail.subject || '',
  from: mail.from?.emailAddress?.address || null,
  from_name: mail.from?.emailAddress?.name || null,
  to: (mail.toRecipients || []).map(r => r.emailAddress?.address).filter(Boolean),
  cc: (mail.ccRecipients || []).map(r => r.emailAddress?.address).filter(Boolean),
  received_at: mail.receivedDateTime || null,
  sent_at: mail.sentDateTime || null,
  body_text,
  body_html,
  body_preview: mail.bodyPreview || '',
  has_attachments: attachments.length > 0 || !!mail.hasAttachments,
  attachment_count: attachments.length,
  attachments,
};

const mailContext = [
  `Subject: ${message.subject || ''}`,
  `From: ${message.from_name || ''} <${message.from || ''}>`,
  `To: ${(message.to || []).join(', ')}`,
  `Cc: ${(message.cc || []).join(', ')}`,
  `Received At: ${message.received_at || ''}`,
  `Sent At: ${message.sent_at || ''}`,
  `Has Attachments: ${message.has_attachments ? 'true' : 'false'}`,
  `Attachment Count: ${message.attachment_count || 0}`,
  `Body Preview: ${message.body_preview || ''}`,
  `Body Text:\n${message.body_text || ''}`
].join('\n');

const payload = {
  event_type: 'asr_email_thread',
  mailbox: seed.mailbox,
  an: seed.an,
  trigger_message_id: seed.trigger_message_id,
  trigger_graph_id: seed.trigger_graph_id,
  trigger_conversation_id: seed.trigger_conversation_id,
  message_count: 1,
  total_attachment_count: attachments.length,
  has_any_attachments: attachments.length > 0 || !!mail.hasAttachments,
  mail_context: mailContext,
  messages: [message],
};

return [{ json: payload }];

const crypto = require('crypto');
const payload = $json;
const rawBody = JSON.stringify(payload);
const secret = $env.HERMES_CARGOLO_ASR_WEBHOOK_SECRET;
if (!secret) { throw new Error('Missing HERMES_CARGOLO_ASR_WEBHOOK_SECRET in n8n env'); }
const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{ json: { rawBody, signature } }];
